import { Component, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { Quiz } from '../../core/models';

@Component({
  selector: 'app-quiz-take',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './quiz-take.component.html',
  styleUrl: './quiz-take.component.css',
})
export class QuizTakeComponent {
  loading = signal(false);
  error = signal<string | null>(null);
  submitting = signal(false);

  courseId = 'c1';

  quiz = signal<Quiz>({
    id: 'q2',
    moduleId: 'm2',
    title: 'CSS Fundamentals Quiz',
    attemptLimit: 2,
    attemptsUsed: 0,
    passed: false,
    questions: [
      {
        id: 'qq1',
        quizId: 'q2',
        text: 'Which CSS property controls the space inside an element, between content and border?',
        options: ['margin', 'padding', 'gap', 'border-spacing'],
      },
      {
        id: 'qq2',
        quizId: 'q2',
        text: 'Which value of display enables Flexbox layout on a container?',
        options: ['block', 'grid', 'flex', 'inline'],
      },
      {
        id: 'qq3',
        quizId: 'q2',
        text: 'What does the selector ".btn" target?',
        options: ['An element with id "btn"', 'Elements with class "btn"', 'The <btn> tag', 'All buttons'],
      },
    ],
  });

  /** answers[questionIndex] = selected option index */
  answers = signal<number[]>([]);

  readonly blocked = computed(() => {
    const q = this.quiz();
    return (q.attemptsUsed ?? 0) >= q.attemptLimit;
  });
  readonly answeredAll = computed(() => {
    const total = this.quiz().questions?.length ?? 0;
    const a = this.answers();
    return total > 0 && a.filter((v) => v !== undefined && v !== null).length === total;
  });

  constructor(private router: Router) {}

  select(qIndex: number, optIndex: number): void {
    this.answers.update((a) => {
      const next = [...a];
      next[qIndex] = optIndex;
      return next;
    });
  }

  isSelected(qIndex: number, optIndex: number): boolean {
    return this.answers()[qIndex] === optIndex;
  }

  submit(): void {
    if (!this.answeredAll() || this.blocked()) return;
    this.submitting.set(true);
    // service_agent wires this to api.submitQuiz(id, answers) then navigates on the response.
    this.router.navigate(['/quizzes', this.quiz().id, 'result']);
  }
}
